/**
 * Generate Calendly firewall config.
 *
 * Data source: https://developer.calendly.com/getting-started
 *
 * Calendly is a scheduling automation platform.
 * Uses Bearer token authentication.
 * Token format: opaque alphanumeric string, no known prefix.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developer.calendly.com/getting-started";
// Token format: opaque alphanumeric string ~40 chars
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe00";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Calendly API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:calendly",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const calendlyFirewall = {",
    '  name: "calendly",',
    '  description: "Calendly API",',
    "  placeholders: {",
    `    CALENDLY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.calendly.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.CALENDLY_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Calendly firewall config...");
  const ts = generateTypeScript();
  writeOutput("calendly", ts, import.meta.dirname);
}
